// Read the current file
const placesFilePath = path.join(__dirname, '../backend/data/placesData.js');
const fileContent = fs.readFileSync(placesFilePath, 'utf8');

// Process the file to update descriptions
let updatedContent = fileContent;

// Iterate through each place name and update description
Object.entries(descriptions).forEach(([placeName, description]) => {
  // Escape special regex characters
  const escapedName = placeName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  
  // Find the place block and update description
  const regex = new RegExp(
    `(name: "${escapedName}",\\s*state: "[^"]*",\\s*stateSlug: "[^"]*",\\s*region: "[^"]*",\\s*category: "[^"]*",\\s*description: ")([^"]*)"`,
    'g'
  );
  
  updatedContent = updatedContent.replace(regex, `$1${description}"`);
});

// Write the updated content back
fs.writeFileSync(placesFilePath, updatedContent, 'utf8');
console.log('✅ Successfully updated descriptions to 6-line format for all places!');
